import React, { useState, useEffect } from 'react';
import PlayerList from '../components/PlayerList';
import AnswerInput from '../components/AnswerInput';
import VotingPanel from '../components/VotingPanel';

export default function Game({ socket, roomCode, playerId, roomState, myQuestion }) {
  const phase = roomState?.phase;
  const [hasAnswered, setHasAnswered] = useState(false);
  const [hasVoted, setHasVoted] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    setHasAnswered(false);
    setHasVoted(false);
    setError('');
  }, [roomState?.currentRound]);

  const handleAnswer = (answer) => {
    socket.emit('submit_answer', { roomCode, playerId, answer }, (res) => {
      if (res.error) return setError(res.error);
      setHasAnswered(true);
      setError('');
    });
  };

  const handleVote = (targetId) => {
    socket.emit('submit_vote', { roomCode, voterId: playerId, targetId }, (res) => {
      if (res.error) return setError(res.error);
      setHasVoted(true);
      setError('');
    });
  };

  const handleMoveToVoting = () => {
    socket.emit('move_to_voting', { roomCode }, (res) => {
      if (res?.error) setError(res.error);
    });
  };

  const handleNextRound = () => {
    socket.emit('next_round', { roomCode });
  };

  const players = roomState?.players || [];
  const myPlayer = players.find(p => p.id === playerId);
  const roundResult = roomState?.roundResult;

  return (
    <div className="card" style={{ maxWidth: 640 }}>
      {/* Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
        <div>
          <span className="tag tag-muted">Runda {roomState?.currentRound} / {roomState?.totalRounds}</span>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <span className="muted" style={{ fontSize: '0.8rem' }}>Ty:</span>
          <span style={{ fontFamily: 'var(--font-head)', fontWeight: 700, color: 'var(--accent2)' }}>
            {myPlayer?.name}
          </span>
          <span className="tag tag-accent">{myPlayer?.score || 0} pkt</span>
        </div>
      </div>

      {/* ANSWERING PHASE */}
      {phase === 'answering' && (
        <>
          <div style={{
            background: 'var(--surface2)',
            border: '1px solid var(--border)',
            borderRadius: 'var(--radius)',
            padding: 20,
            marginBottom: 24
          }}>
            <span className="muted" style={{ fontSize: '0.8rem', textTransform: 'uppercase', letterSpacing: '0.08em' }}>
              Twoje pytanie
            </span>
            <p style={{
              fontFamily: 'var(--font-head)',
              fontSize: '1.25rem',
              fontWeight: 700,
              marginTop: 8,
              lineHeight: 1.4
            }}>
              {myQuestion?.question || 'Ładowanie pytania...'}
            </p>
          </div>

          {!hasAnswered ? (
            <AnswerInput onSubmit={handleAnswer} />
          ) : (
            <div style={{ textAlign: 'center', padding: 20 }}>
              <span className="tag tag-green">✓ Odpowiedź wysłana!</span>
              <p className="muted" style={{ marginTop: 12 }}>
                Czekamy na pozostałych... ({roomState?.answersCount}/{players.filter(p => p.connected).length})
              </p>
            </div>
          )}

          {error && <div className="error-msg">{error}</div>}
        </>
      )}

      {/* REVEAL PHASE */}
      {phase === 'reveal' && (
        <>
          <h2 style={{ marginBottom: 4 }}>Odpowiedzi wszystkich</h2>
          <p className="muted" style={{ marginBottom: 20 }}>
            Pytanie było: <strong style={{ color: 'var(--text)' }}>{roomState?.roundResult ? '???' : '???'}</strong>{' '}
            Czy ktoś odpowiedział inaczej?
          </p>

          <div style={{ display: 'flex', flexDirection: 'column', gap: 10, marginBottom: 24 }}>
            {Object.entries(roomState?.answers || {}).map(([pid, answer]) => {
              const player = players.find(p => p.id === pid);
              return (
                <div key={pid} style={{
                  background: 'var(--surface2)',
                  border: '1px solid var(--border)',
                  borderRadius: 8,
                  padding: '12px 16px',
                  display: 'flex',
                  justifyContent: 'space-between',
                  alignItems: 'flex-start',
                  gap: 12
                }}>
                  <span style={{ fontFamily: 'var(--font-head)', fontWeight: 700, color: 'var(--accent2)', whiteSpace: 'nowrap' }}>
                    {player?.name || '?'}
                  </span>
                  <span style={{ color: 'var(--text)', textAlign: 'right' }}>{answer}</span>
                </div>
              );
            })}
          </div>

          <div style={{
            background: 'rgba(255,77,109,0.08)',
            border: '1px solid rgba(255,77,109,0.3)',
            borderRadius: 8,
            padding: 16,
            marginBottom: 24
          }}>
            <span className="muted" style={{ fontSize: '0.8rem', textTransform: 'uppercase' }}>Normalne pytanie było:</span>
            <p style={{ fontFamily: 'var(--font-head)', fontWeight: 700, marginTop: 6, color: 'var(--text)' }}>
              {roomState?.roundResult?.normalQuestion || myQuestion?.question}
            </p>
          </div>

          <button className="btn btn-primary" style={{ width: '100%' }} onClick={handleMoveToVoting}>
            ▶ Przejdź do głosowania
          </button>
        </>
      )}

      {/* VOTING PHASE */}
      {phase === 'voting' && (
        <>
          <h2 style={{ marginBottom: 4 }}>Kto jest impostorem?</h2>
          <p className="muted" style={{ marginBottom: 20 }}>
            Zastanów się, czyja odpowiedź brzmiała inaczej...
          </p>

          {!hasVoted ? (
            <VotingPanel
              players={players.filter(p => p.id !== playerId)}
              onVote={handleVote}
            />
          ) : (
            <div style={{ textAlign: 'center', padding: 20 }}>
              <span className="tag tag-green">✓ Zagłosowałeś!</span>
              <p className="muted" style={{ marginTop: 12 }}>
                Czekamy na pozostałych... ({roomState?.votesCount}/{players.filter(p => p.connected).length})
              </p>
            </div>
          )}

          {error && <div className="error-msg">{error}</div>}
        </>
      )}

      {/* RESULT PHASE */}
      {phase === 'result' && roundResult && (
        <>
          <h2 style={{ marginBottom: 20 }}>Wyniki rundy {roomState.currentRound}</h2>

          <div style={{
            background: roundResult.impostorCaught ? 'rgba(77,255,180,0.08)' : 'rgba(255,77,109,0.08)',
            border: `1px solid ${roundResult.impostorCaught ? 'rgba(77,255,180,0.3)' : 'rgba(255,77,109,0.3)'}`,
            borderRadius: 10,
            padding: 20,
            marginBottom: 20,
            textAlign: 'center'
          }}>
            {roundResult.impostorCaught ? (
              <>
                <div style={{ fontSize: '2rem', marginBottom: 8 }}>🎯</div>
                <h3 style={{ color: 'var(--accent2)' }}>Impostor złapany!</h3>
                <p className="muted" style={{ marginTop: 4 }}>Wszyscy gracze (oprócz impostora) dostają +1 pkt</p>
              </>
            ) : (
              <>
                <div style={{ fontSize: '2rem', marginBottom: 8 }}>🕵️</div>
                <h3 style={{ color: 'var(--accent)' }}>Impostor uciekł!</h3>
                <p className="muted" style={{ marginTop: 4 }}>Impostor dostaje +2 pkt</p>
              </>
            )}
          </div>

          <div style={{ marginBottom: 16 }}>
            <p className="muted" style={{ marginBottom: 8, fontSize: '0.8rem', textTransform: 'uppercase' }}>Impostor był:</p>
            <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
              <span className="tag tag-accent">
                {players.find(p => p.id === roundResult.impostorId)?.name || '?'}
              </span>
              <span className="muted" style={{ fontSize: '0.9rem' }}>
                Ich pytanie: <em>"{roundResult.impostorQuestion}"</em>
              </span>
            </div>
          </div>

          <div style={{ marginBottom: 20 }}>
            <p className="muted" style={{ marginBottom: 8, fontSize: '0.8rem', textTransform: 'uppercase' }}>Normalne pytanie:</p>
            <p style={{ fontFamily: 'var(--font-head)', fontWeight: 600 }}>{roundResult.normalQuestion}</p>
          </div>

          <div style={{ marginBottom: 24 }}>
            <p className="muted" style={{ marginBottom: 10, fontSize: '0.8rem', textTransform: 'uppercase' }}>Głosy:</p>
            {Object.entries(roundResult.voteCounts || {}).map(([pid, count]) => {
              const p = players.find(pl => pl.id === pid);
              return (
                <div key={pid} style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 6 }}>
                  <span style={{ fontFamily: 'var(--font-head)', fontWeight: 700, minWidth: 80 }}>{p?.name}</span>
                  <div style={{
                    flex: 1,
                    height: 8,
                    background: 'var(--surface2)',
                    borderRadius: 4,
                    overflow: 'hidden'
                  }}>
                    <div style={{
                      width: `${(count / players.length) * 100}%`,
                      height: '100%',
                      background: pid === roundResult.impostorId ? 'var(--accent)' : 'var(--accent2)',
                      borderRadius: 4,
                      transition: 'width 0.6s ease'
                    }} />
                  </div>
                  <span style={{ fontFamily: 'var(--font-head)', fontWeight: 700, minWidth: 20 }}>{count}</span>
                  {pid === roundResult.impostorId && <span className="tag tag-accent" style={{ fontSize: '0.7rem' }}>imp</span>}
                </div>
              );
            })}
          </div>

          <div style={{ borderTop: '1px solid var(--border)', paddingTop: 20, marginBottom: 20 }}>
            <p className="muted" style={{ marginBottom: 10, fontSize: '0.8rem', textTransform: 'uppercase' }}>Aktualny ranking:</p>
            <PlayerList players={players} showScore />
          </div>

          <button className="btn btn-primary" style={{ width: '100%' }} onClick={handleNextRound}>
            {roomState.currentRound >= roomState.totalRounds ? '🏆 Zakończ grę' : '▶ Następna runda'}
          </button>
        </>
      )}
    </div>
  );
}
